assignments.value:
={{
"You are Study Aura, an educational audio overview script generator. Create a narration script for the topic: " + ($json.body.topic || "General Study") + ". Style: " + ($json.body.style || "podcast") + ". Length: " + ($json.body.length || "standard") + ".\n\n" +
"Selected source context:\n" +
(
  Array.isArray($json.body.selectedSources) && $json.body.selectedSources.length > 0
    ? $json.body.selectedSources.map((source, index) => {
        return (index + 1) + ". " + (source.title || "Untitled Source") + " [" + (source.type || "source") + "]\n" +
          "Summary or content: " + (source.summary || source.value || "No summary provided.");
      }).join("\n\n")
    : "No selected sources were provided. Use the topic only."
) +
"\n\nReturn ONLY valid JSON. No markdown. No code fences.\n" +
"Required JSON format: {\"title\": string, \"description\": string, \"estimatedDuration\": string, \"segments\": [{\"speaker\": string, \"text\": string}], \"recap\": string[]}.\n" +
"Rules:\n" +
"- Use 3 to 6 segments.\n" +
"- If style is podcast, use Host A and Host B.\n" +
"- If style is calm or energetic, use Narrator as speaker.\n" +
"- Segment text should sound natural when read aloud.\n" +
"- Recap should contain 3 to 5 short takeaways.\n" +
"- Prioritize selected source context when available.\n" +
"- Do not include markdown, comments, or text outside JSON."
}}

parameters.jsCode:
const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let audioOverview;
let fallback = false;

try {
  audioOverview = JSON.parse(cleaned);

  if (!audioOverview.title || !Array.isArray(audioOverview.segments)) {
    throw new Error("Invalid audio overview format");
  }
} catch (error) {
  fallback = true;
  audioOverview = {
    title: "Study Aura Audio Overview",
    description: "A quick fallback narration script for reviewing a study topic.",
    estimatedDuration: "1 minute",
    segments: [
      {
        speaker: "Narrator",
        text: "Welcome to this Study Aura audio overview. In this short review, we will focus on the main idea, important details, and a simple way to remember the topic."
      },
      {
        speaker: "Narrator",
        text: "Start by identifying the key concept. Then connect it to examples, definitions, and review questions so the idea becomes easier to recall."
      }
    ],
    recap: ["Identify the main idea", "Connect details with examples", "Review using active recall"]
  };
}

const segments = Array.isArray(audioOverview.segments)
  ? audioOverview.segments.map((segment) => ({
      speaker: String(segment.speaker || "Narrator"),
      text: String(segment.text || "Review this topic carefully.")
    }))
  : [];

const recap = Array.isArray(audioOverview.recap)
  ? audioOverview.recap.map((item) => String(item)).slice(0, 5)
  : ["Review the main idea", "Practice recall", "Connect examples"];

return [
  {
    json: {
      audioOverview: {
        title: String(audioOverview.title || "Study Aura Audio Overview"),
        description: String(audioOverview.description || "Generated audio overview script."),
        estimatedDuration: String(audioOverview.estimatedDuration || "2 minutes"),
        segments,
        recap
      },
      fallback,
      provider: $json.provider || "gemini"
    }
  }
];

